import { formatMessageTime } from '@/ui/web/chat/utils/formatMessageTime'
import { describe, expect, it } from 'vitest'

describe('formatMessageTime', () => {
  describe('today — time only', () => {
    it('returns HH:mm for a timestamp from today in English', () => {
      const now = new Date()
      const todayTs = new Date(
        now.getFullYear(),
        now.getMonth(),
        now.getDate(),
        14,
        32,
        0,
      ).toISOString()

      const result = formatMessageTime(todayTs, 'en')
      expect(result).toMatch(/^\d{2}:\d{2}$/)
    })

    it('returns HH:mm for a timestamp from today in Hebrew', () => {
      const now = new Date()
      const todayTs = new Date(
        now.getFullYear(),
        now.getMonth(),
        now.getDate(),
        9,
        5,
        0,
      ).toISOString()

      const result = formatMessageTime(todayTs, 'he')
      expect(result).toMatch(/^\d{2}:\d{2}$/)
    })
  })

  describe('older than today — short date + time', () => {
    it('returns "MMM D, HH:mm" for yesterday in English', () => {
      const yesterday = new Date()
      yesterday.setDate(yesterday.getDate() - 1)
      const ts = new Date(
        yesterday.getFullYear(),
        yesterday.getMonth(),
        yesterday.getDate(),
        18,
        45,
        0,
      ).toISOString()

      const result = formatMessageTime(ts, 'en')
      // e.g. "May 10, 18:45"
      expect(result).toMatch(/^[A-Z][a-z]{2} \d{1,2}, \d{2}:\d{2}$/)
    })

    it('returns Hebrew date format for older messages in Hebrew', () => {
      const twoDaysAgo = new Date()
      twoDaysAgo.setDate(twoDaysAgo.getDate() - 2)
      const ts = new Date(
        twoDaysAgo.getFullYear(),
        twoDaysAgo.getMonth(),
        twoDaysAgo.getDate(),
        10,
        0,
        0,
      ).toISOString()

      const result = formatMessageTime(ts, 'he')
      // Hebrew format: "11 במאי, 10:00" — Hebrew month names contain Hebrew characters
      expect(result).toMatch(/במאי/)
      expect(result).toMatch(/\d{2}:\d{2}$/)
    })
  })

  describe('invalid input', () => {
    it('returns empty string for undefined', () => {
      expect(formatMessageTime(undefined, 'en')).toBe('')
    })

    it('returns empty string for null', () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      expect(formatMessageTime(null as any, 'en')).toBe('')
    })

    it('returns empty string for invalid date string', () => {
      expect(formatMessageTime('not-a-date', 'en')).toBe('')
    })

    it('returns empty string for empty string', () => {
      expect(formatMessageTime('', 'en')).toBe('')
    })
  })

  describe('locale fallback', () => {
    it('falls back to en-US for unknown locale', () => {
      const now = new Date()
      const todayTs = new Date(
        now.getFullYear(),
        now.getMonth(),
        now.getDate(),
        12,
        0,
        0,
      ).toISOString()

      const result = formatMessageTime(todayTs, 'fr')
      expect(result).toMatch(/^\d{2}:\d{2}$/)
    })
  })
})

/**
 * Format a message timestamp for display in a chat bubble.
 *
 * - Same calendar day as today: "14:32" (en) or "14:32" (he — uses Gregorian calendar)
 * - Older: "May 11, 14:32" (en) or "11 במאי, 14:32" (he)
 *
 * @param timestamp - ISO 8601 string (e.g. from new Date().toISOString())
 * @param locale - IETF BCP 47 locale tag, e.g. "en" or "he"
 * @returns Formatted time string, or empty string if timestamp is invalid
 */
export function formatMessageTime(timestamp: string | undefined, locale: string): string {
  if (!timestamp) return ''

  const date = new Date(timestamp)
  if (isNaN(date.getTime())) return ''

  const now = new Date()

  // Compare calendar dates using local time (same day = today)
  const isToday =
    date.getFullYear() === now.getFullYear() &&
    date.getMonth() === now.getMonth() &&
    date.getDate() === now.getDate()

  const timeOptions: Intl.DateTimeFormatOptions = {
    hour: '2-digit',
    minute: '2-digit',
    hour12: false, // Always 24-hour for consistency; matches "14:32" style in issue
  }

  if (isToday) {
    return new Intl.DateTimeFormat(locale === 'he' ? 'he-IL' : 'en-US', timeOptions).format(date)
  }

  const fullOptions: Intl.DateTimeFormatOptions = {
    ...timeOptions,
    month: 'short', // "May" / "במאי"
    day: 'numeric',
  }

  return new Intl.DateTimeFormat(locale === 'he' ? 'he-IL' : 'en-US', fullOptions).format(date)
}

